/**
 * Función de compatibilidad con el monolito.
 * @deprecated Usar createApoloClient
 */
export const requestCustomApi = async (method, parameters, customApi, xrmContext) => {
  try {
    const url = xrmContext.Utility.getGlobalContext().getClientUrl()
    const response = await fetch(`${url}/api/data/v9.2/${customApi}`, {
      method,
      headers: {
        'OData-MaxVersion': '4.0',
        'OData-Version': '4.0',
        'Content-Type': 'application/json; charset=utf-8',
        Accept: 'application/json',
      },
      body: JSON.stringify(parameters),
    })
    return await response.json()
  } catch {
    return { Error: `Error al llamar a custom api ${customApi}`, Response: null }
  }
}
